<template><form class="login" @submit.prevent="submit"><h1>Replay Login</h1><input v-model="username" placeholder="Username"><input v-model="password" placeholder="Password" type="password"><button>Login</button></form></template><script setup>import {ref} from 'vue';import {useRouter} from 'vue-router';import {useAuthStore} from '../stores/auth';const username=ref('');const password=ref('');const router=useRouter();const auth=useAuthStore();async function submit(){await auth.login(username.value,password.value);router.push('/')}</script>
